import Welcome from './Components/Welcome';
import { Route, Router } from 'react-router';

function App() {
  return (
    <Router>
      <div className="App">
        <Link to= '/Registration'>Registration</Link>
      <Welcome></Welcome>
      <Switch>

        <Route path='/' exact>
        <Registration/>
        </Route>
      </Switch>
    </div>
    </Router>
  );
}

export default App;
